#include <bits/stdc++.h>
using namespace std;
#define int long long
int n,ans,a,b,f=1;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	while(n--) {
		int k,d,e;
		cin>>k>>d>>e;
		ans=d*e-1;
		f=1;
		for(int i=1; i*i<=k; i++) {
			if(k%i==0) {
				a=i-1;
				b=k/i-1;
				if(a*b==ans) {
					cout<<a+1<<" "<<b+1<<"\n";
					f=0;
					break;
				}
			}
		}
		if(f) {
			cout<<"NO\n";
		}
	}
	return 0;
}
